// Rust-faithful Dafny port of src/runtime/shell/states/Expansion.rs::do_brace_expand.
// The Rust function delegates brace parsing/expansion to bun_shell_parser::braces;
// this file keeps that boundary as small mechanical helpers and preserves the
// state/output update order of do_brace_expand.

datatype ExpansionState = Idle | Walking | CmdSubst | Glob | BraceExpand | Done | Err

class ExpansionOut {
  var buf: seq<int>
  var bounds: seq<int>

  constructor ()
    ensures buf == []
    ensures bounds == []
  {
    buf := [];
    bounds := [];
  }
}

class Atom {
  var has_glob_expansion: bool

  constructor (hasGlob: bool)
    ensures has_glob_expansion == hasGlob
  {
    has_glob_expansion := hasGlob;
  }
}

class Expansion {
  var node: Atom
  var out: ExpansionOut
  var current_out: seq<int>
  var state: ExpansionState

  constructor (atom: Atom)
    requires atom != null
    ensures node == atom
    ensures out != null
    ensures current_out == []
    ensures state == Idle
  {
    node := atom;
    out := new ExpansionOut();
    current_out := [];
    state := Idle;
  }
}

class LexerOutput {
  var tokens: seq<int>
  var contains_nested: bool

  constructor (tokens_: seq<int>, contains_nested_: bool)
    ensures tokens == tokens_
    ensures contains_nested == contains_nested_
  {
    tokens := tokens_;
    contains_nested := contains_nested_;
  }
}

function IsAllAscii(s: seq<int>): bool
{
  forall i :: 0 <= i < |s| ==> 0 <= s[i] < 128
}

function method IndexOf(s: seq<int>, c: int, i: nat): nat
  requires i <= |s|
  ensures IndexOf(s, c, i) <= |s|
  decreases |s| - i
{
  if i == |s| then |s|
  else if s[i] == c then i
  else IndexOf(s, c, i + 1)
}

function ContainsNestedBraces(tokens: seq<int>): bool
{
  false
}

method TokenizeAscii(src: seq<int>) returns (output: LexerOutput)
  ensures output != null
  ensures output.tokens == src
{
  output := new LexerOutput(src, ContainsNestedBraces(src));
}

method TokenizeWtf8(src: seq<int>) returns (output: LexerOutput)
  ensures output != null
  ensures output.tokens == src
{
  output := new LexerOutput(src, ContainsNestedBraces(src));
}

function SimpleBraceExpanded(tokens: seq<int>): seq<seq<int>>
{
  var open := IndexOf(tokens, 123, 0); // '{'
  if open < |tokens| then
    var close := IndexOf(tokens, 125, open + 1); // '}'
    if close < |tokens| then
      var comma := IndexOf(tokens, 44, open + 1); // ','
      if comma < close then
        [tokens[..open] + tokens[open + 1..comma] + tokens[close + 1..],
         tokens[..open] + tokens[comma + 1..close] + tokens[close + 1..]]
      else [tokens]
    else [tokens]
  else [tokens]
}

function CalculateExpandedAmount(tokens: seq<int>): nat
{
  |SimpleBraceExpanded(tokens)|
}

method BracesExpand(tokens: seq<int>, count: nat, contains_nested: bool) returns (expanded: seq<seq<int>>)
  ensures expanded == SimpleBraceExpanded(tokens)
{
  expanded := SimpleBraceExpanded(tokens);
}

method DoBraceExpand(me: Expansion)
  requires me != null
  requires me.node != null
  requires me.out != null
  modifies me, me.out
{
  var brace_str := me.current_out;
  var lexer_output: LexerOutput;
  if IsAllAscii(brace_str) {
    lexer_output := TokenizeAscii(brace_str);
  } else {
    lexer_output := TokenizeWtf8(brace_str);
  }
  var count := CalculateExpandedAmount(lexer_output.tokens);
  var expanded := BracesExpand(lexer_output.tokens, count, lexer_output.contains_nested);

  me.current_out := [];
  var i := 0;
  while i < |expanded|
    invariant 0 <= i <= |expanded|
    modifies me, me.out
    decreases |expanded| - i
  {
    var s := expanded[i];
    if |me.out.buf| != 0 {
      me.out.bounds := me.out.bounds + [|me.out.buf|];
    }
    me.out.buf := me.out.buf + s;
    i := i + 1;
  }

  var atom := me.node;
  if atom.has_glob_expansion {
    me.state := Done;
  } else {
    me.state := Done;
  }
}

method SanityCheck_DoBraceExpand()
{
  var atom := new Atom(false);
  var me := new Expansion(atom);
  me.current_out := [97, 123, 98, 44, 99, 125, 100]; // a{b,c}d
  DoBraceExpand(me);
  assert me.current_out == [];
  assert me.out.buf == [97, 98, 100, 97, 99, 100]; // abdacd
  assert me.out.bounds == [3];
  assert me.state == Done;
}

